`timescale 1ns / 1ps
module CNN_top(
input       wire                        clk,    
input       wire                        enable,
input       wire                        rst_n,
input       wire signed [55:0]          data_in,//输入特征图，每次7*8bit
output      reg                         enable_out,
output      wire signed [63:0]          data_out//最终注意力分数，两个32bit拼接
    );
    
reg [7:0] cnt;
genvar i;
parameter cnt_max = 8'd153;//计数器最大值，根据需要调整
reg [2:0] counter;//记录cnt到达max的次数，达到8次时表示完成了的卷积计算

// counter，PE arry设计为4通道，counter用于记录现在为第几个四通道，最小0，最大7
always @(posedge clk or negedge rst_n) begin
    if(!rst_n)
        counter <= 3'b0;
    else if(cnt == cnt_max) begin
        if(counter == 3'b111) begin
            counter <= 3'b0;
        end
        else begin
            counter <= counter + 1;
        end
    end
    else
        counter <= counter;
end
// cnt
always @(posedge clk or negedge rst_n)begin
    if(!rst_n)
        cnt <= 8'b0;
    else if(enable)begin
        if (cnt == cnt_max) begin
            if(counter == 3'b111) begin
                cnt <= 8'd0;
            end
            else begin
                cnt <= 8'd11;
            end
        end
        else 
            cnt <= cnt + 1;
    end
    
    else
        cnt <= cnt;
end

//enable_out
always @(posedge clk or negedge rst_n)begin
    if(!rst_n)
        enable_out <= 1'b0;
    else if(cnt == 8'd152 ||cnt == 8'd153)//输出使能在T153和T154两个周期拉高，输出两个注意力分数
        enable_out <= 1'b1;
    else
        enable_out <= 1'b0;
end

//SA1第一层卷积
wire    signed  [32*616-1:0]    weight_1;//32通道*11*7 个权重，每个8bit
wire    signed  [4*32-1:0]     data_o_1;//SA1输出的4通道卷积结果，每个通道32bit
wire    signed  [32*16-1:0]     bias_1;//32通道偏置，每个16bit
wire    signed  [4*32-1:0]     after_bias_1;
wire    signed  [4*8-1:0]      after_quant_1;
wire    signed  [4*8-1:0]      after_relu_1;
